refentry.refsect1:
&reftitle.description;
public Yaf_Application::__construct mixedconfig stringenviron
Erzeugt eine Instanz von Yaf_Application.

  &reftitle.examples;

   Beispiel für Yaf_Application::__construct


<?php
defined('APPLICATION_PATH')                  // APPLICATION_PATH wird in der ini-Konfigurationsdatei verwendet
    || define('APPLICATION_PATH', __DIR__);

$application = new Yaf_Application(APPLICATION_PATH.'/conf/application.ini');
$application->bootstrap()->run();
?>


   &example.outputs.similar;






   Beispiel für Yaf_Application::__construct


<?php
$config = array(
    "application" => array(
        "directory" => realpath(dirname(__FILE__)) . "/application",
    ),
);

/** Yaf_Application */
$application = new Yaf_Application($config);
$application->bootstrap()->run();
?>


   &example.outputs.similar;
